with WithAncestors AS (SELECT itemid FROM AncestorIds2 WHERE AncestorId in (100) ),WithItemLinkItemIds AS (select ItemLinks2.LinkedId From ItemLinks2 join withancestors on withancestors.itemid=itemlinks2.itemid  where ItemLinks2.Type in (2,3))select A.Id,A.Name from mediaitems A join fts_search9 on A.Id=fts_search9.RowId and fts_search9 match @SearchTerm where Exists (select 1 From ItemLinks2 join ancestorids2 on ancestorids2.itemid=itemlinks2.itemid and ancestorids2.ancestorid in (100)  where ItemLinks2.LinkedId = A.Id AND ItemLinks2.Type in (2,3)) ORDER BY Rank ASC LIMIT 12
